{"content": "package agent

import (
	"encoding/json"
	"fmt"
	"log"
	"sync"
	"time"
)

// MessageRole constants.
const (
	RoleUser      = "user"
	RoleAssistant = "assistant"
	RoleTool      = "tool"
	RoleSystem    = "system"
)

// Message represents a single message in the conversation.
type Message struct {
	Role       string            `json:"role"`
	Content    string            `json:"content,omitempty"`
	ToolCallID string            `json:"tool_call_id,omitempty"`
	ToolName   string            `json:"tool_name,omitempty"`
	ToolCalls  []ToolCallMessage `json:"tool_calls,omitempty"`
}

// ToolCallMessage is the LLM-format tool call inside an assistant message.
type ToolCallMessage struct {
	ID       string `json:"id"`
	Type     string `json:"type"`
	Function struct {
		Name      string `json:"name"`
		Arguments string `json:"arguments"`
	} `json:"function"`
}

// Session holds the state for one conversation.
type Session struct {
	ID           string    `json:"id"`
	Title        string    `json:"title"`
	Messages     []Message `json:"messages"`
	CreatedAt    time.Time `json:"created_at"`
	TurnCount    int       `json:"turn_count"`
	Status       string    `json:"status,omitempty"`
	StatusDetail string    `json:"status_detail,omitempty"`
}

// SessionManager manages multiple independent sessions with disk persistence.
type SessionManager struct {
	mu       sync.RWMutex
	sessions map[string]*Session
	store    *Store
}

// NewSessionManager creates a new session manager backed by a Store.
func NewSessionManager(store *Store) *SessionManager {
	sm := &SessionManager{
		sessions: make(map[string]*Session),
		store:    store,
	}
	// Preload existing sessions from disk.
	ids, err := store.List()
	if err != nil {
		log.Printf("Warning: failed to list sessions: %v", err)
		return sm
	}
	for _, id := range ids {
		sess, err := store.Load(id)
		if err != nil {
			log.Printf("Warning: failed to load session %s: %v", id, err)
			continue
		}
		if sess != nil {
			sm.sessions[id] = sess
		}
	}
	return sm
}

// GetOrCreate returns an existing session or creates a new one (persisted).
func (sm *SessionManager) GetOrCreate(id string) *Session {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	if s, ok := sm.sessions[id]; ok {
		return s
	}
	// Try loading from disk.
	s, err := sm.store.Load(id)
	if err != nil {
		log.Printf("Warning: failed to load session %s: %v", id, err)
	}
	if s != nil {
		sm.sessions[id] = s
		return s
	}
	// Create new.
	s = &Session{
		ID:        id,
		Messages:  []Message{},
		CreatedAt: time.Now(),
	}
	sm.sessions[id] = s
	if err := sm.store.Save(s); err != nil {
		log.Printf("Warning: failed to persist new session %s: %v", id, err)
	}
	return s
}

// Get returns a session by ID, or nil if not found.
func (sm *SessionManager) Get(id string) *Session {
	sm.mu.RLock()
	defer sm.mu.RUnlock()
	return sm.sessions[id]
}

// List returns all session IDs.
func (sm *SessionManager) List() []string {
	sm.mu.RLock()
	defer sm.mu.RUnlock()
	ids := make([]string, 0, len(sm.sessions))
	for id := range sm.sessions {
		ids = append(ids, id)
	}
	return ids
}

// Save persists a session to disk immediately.
func (sm *SessionManager) Save(id string) error {
	sm.mu.RLock()
	sess, ok := sm.sessions[id]
	sm.mu.RUnlock()
	if !ok {
		return fmt.Errorf("session %s not found", id)
	}
	return sm.store.Save(sess)
}

// SaveAll persists all in-memory sessions to disk.
func (sm *SessionManager) SaveAll() {
	sm.mu.RLock()
	ids := make([]string, 0, len(sm.sessions))
	for id := range sm.sessions {
		ids = append(ids, id)
	}
	sm.mu.RUnlock()
	for _, id := range ids {
		if err := sm.Save(id); err != nil {
			log.Printf("Warning: failed to save session %s: %v", id, err)
		}
	}
}

// Delete removes a session.
func (sm *SessionManager) Delete(id string) {
	sm.mu.Lock()
	delete(sm.sessions, id)
	sm.mu.Unlock()
	if err := sm.store.Delete(id); err != nil {
		log.Printf("Warning: failed to delete session file %s: %v", id, err)
	}
}

// AddUserMessage adds a user message to a session and persists.
func (s *Session) AddUserMessage(content string) {
	s.Messages = append(s.Messages, Message{Role: RoleUser, Content: content})
	s.TurnCount++
}

// AddAssistantMessage adds an assistant text message.
func (s *Session) AddAssistantMessage(content string) {
	s.Messages = append(s.Messages, Message{Role: RoleAssistant, Content: content})
}

// AddAssistantToolCallMessage adds an assistant message containing tool calls.
func (s *Session) AddAssistantToolCallMessage(tcs []ToolCallMessage) {
	s.Messages = append(s.Messages, Message{Role: RoleAssistant, Content: "", ToolCalls: tcs})
}

// AddToolResult adds a tool result message.
func (s *Session) AddToolResult(toolCallID, toolName, result string, isError bool) {
	content := result
	if isError {
		content = fmt.Sprintf("Error: %s", result)
	}
	s.Messages = append(s.Messages, Message{
		Role:       RoleTool,
		ToolCallID: toolCallID,
		ToolName:   toolName,
		Content:    content,
	})
}

// MessagesForDisplay returns simplified messages for the frontend (no tool internals).
func (s *Session) MessagesForDisplay() []map[string]string {
	out := make([]map[string]string, 0, len(s.Messages))
	for _, m := range s.Messages {
		switch m.Role {
		case RoleUser:
			out = append(out, map[string]string{"role": "user", "content": m.Content})
		case RoleAssistant:
			if len(m.ToolCalls) > 0 {
				// Summarize tool calls for display.
				var summary string
				for _, tc := range m.ToolCalls {
					if summary != "" {
						summary += "\n"
					}
					summary += fmt.Sprintf("🔧 调用工具: %s(%s)", tc.Function.Name, tc.Function.Arguments)
				}
				out = append(out, map[string]string{"role": "assistant", "content": summary})
				if m.Content != "" {
					out = append(out, map[string]string{"role": "assistant", "content": m.Content})
				}
			} else {
				out = append(out, map[string]string{"role": "assistant", "content": m.Content})
			}
		case RoleTool:
			content := m.Content
			if len(content) > 500 {
				content = content[:500] + "..."
			}
			label := "📎 工具结果"
			out = append(out, map[string]string{"role": "tool", "content": fmt.Sprintf("%s [%s]:\n%s", label, m.ToolName, content)})
		}
	}
	return out
}

// ToOpenAIMessages converts session messages to OpenAI API format.
func (s *Session) ToOpenAIMessages() []map[string]any {
	out := make([]map[string]any, 0, len(s.Messages))
	for _, m := range s.Messages {
		switch m.Role {
		case RoleUser:
			out = append(out, map[string]any{
				"role":    RoleUser,
				"content": m.Content,
			})
		case RoleAssistant:
			msg := map[string]any{"role": RoleAssistant}
			if len(m.ToolCalls) > 0 {
				if m.Content != "" {
					msg["content"] = m.Content
				}
				tcs := make([]map[string]any, len(m.ToolCalls))
				for i, tc := range m.ToolCalls {
					tcs[i] = map[string]any{
						"id":   tc.ID,
						"type": "function",
						"function": map[string]any{
							"name":      tc.Function.Name,
							"arguments": tc.Function.Arguments,
						},
					}
				}
				msg["tool_calls"] = tcs
			} else {
				msg["content"] = m.Content
			}
			out = append(out, msg)
		case RoleTool:
			out = append(out, map[string]any{
				"role":          RoleTool,
				"tool_call_id":  m.ToolCallID,
				"content":       m.Content,
			})
		}
	}
	return out
}

// TrimToLastN keeps only the last N messages, removing orphaned tool messages.
func (s *Session) TrimToLastN(n int) {
	if len(s.Messages) <= n {
		return
	}
	// Always keep the oldest user message for context, then the last n-1.
	kept := []Message{s.Messages[0]}
	kept = append(kept, s.Messages[len(s.Messages)-(n-1):]...)

	// Remove tool messages whose matching tool_calls were trimmed away.
	activeIDs := make(map[string]bool)
	for _, m := range kept {
		for _, tc := range m.ToolCalls {
			activeIDs[tc.ID] = true
		}
	}
	filtered := make([]Message, 0, len(kept))
	for _, m := range kept {
		if m.Role == RoleTool && !activeIDs[m.ToolCallID] {
			continue
		}
		filtered = append(filtered, m)
	}
	s.Messages = filtered
}
