func (s *Session) MessagesForDisplay() []DisplayMsg {
	var out []DisplayMsg
	var thinking []string // accumulated tool lines

	flushThinking := func() {
		if len(thinking) == 0 {
			return
		}
		content := ""
		for _, line := range thinking {
			if content != "" {
				content += "\n"
			}
			content += line
		}
		out = append(out, DisplayMsg{
			Role:    "assistant",
			Content: content,
			Summary: fmt.Sprintf("思考过程 (%d步)", len(thinking)),
			Type:    "thinking",
		})
		thinking = nil
	}

