		switch m.Role {
		case RoleUser:
			flushThinking()
			out = append(out, DisplayMsg{Role: "user", Content: m.Content, Type: "message"})
		case RoleAssistant:
			if len(m.ToolCalls) > 0 {
				// Tool-call phase: accumulate into thinking block.
				for _, tc := range m.ToolCalls {
					thinking = append(thinking, fmt.Sprintf("🔧 %s(%s)", tc.Function.Name, tc.Function.Arguments))
				}
			} else {
				// Text response: flush any accumulated thinking, then output.
				flushThinking()
				if m.Content != "" {
					out = append(out, DisplayMsg{Role: "assistant", Content: m.Content, Type: "message"})
				}
			}
		case RoleTool:
			content := m.Content
			if len(content) > 500 {
				content = content[:500] + "..."
			}
			thinking = append(thinking, fmt.Sprintf("📎 %s:\n%s", m.ToolName, content))
		}
	}
	flushThinking()
	return out
