{"file_path": "C:/Users/zheng/Desktop/crush-agent/internal/agent/session.go", "new_string": "// DisplayMsg is a message formatted for the frontend.
type DisplayMsg struct {
	Role    string `json:"role"`
	Content string `json:"content"`
	Summary string `json:"summary,omitempty"`
	Type    string `json:"type,omitempty"` // "thinking", "message"
}

// MessagesForDisplay returns messages for the frontend.
// Each turn's tool calls+results are grouped into a single "thinking"
// block whose Content is pre-built HTML with individual collapsible
// <details> elements for each tool step.
func (s *Session) MessagesForDisplay() []DisplayMsg {
	var out []DisplayMsg

	// Accumulate tool step HTML fragments for the current "thinking" block.
	var steps []string

	flushThinking := func() {
		if len(steps) == 0 {
			return
		}
		content := ""
		for _, s := range steps {
			content += s
		}
		out = append(out, DisplayMsg{
			Role:    "assistant",
			Content: content,
			Summary: fmt.Sprintf("思考过程 (%d步)", len(steps)),
			Type:    "thinking",
		})
		steps = nil
	}

	for _, m := range s.Messages {
		switch m.Role {
		case RoleUser:
			flushThinking()
			out = append(out, DisplayMsg{Role: "user", Content: m.Content, Type: "message"})
		case RoleAssistant:
			if len(m.ToolCalls) > 0 {
				for _, tc := range m.ToolCalls {
					steps = append(steps, fmt.Sprintf(
						"<details><summary>🔧 %s</summary><div style=\"margin-top:4px;padding-top:4px;border-top:1px solid rgba(0,0,0,.06);font-size:13px;line-height:1.5\">参数: %s</div></details>",
						escHTML(tc.Function.Name), escHTML(tc.Function.Arguments)))
				}
			}
			if m.Content != "" {
				flushThinking()
				out = append(out, DisplayMsg{Role: "assistant", Content: m.Content, Type: "message"})
			}
		case RoleTool:
			content := m.Content
			if len(content) > 500 {
				content = content[:500] + "..."
			}
			steps = append(steps, fmt.Sprintf(
				"<details><summary>📎 %s</summary><div style=\"margin-top:4px;padding-top:4px;border-top:1px solid rgba(0,0,0,.06);font-size:13px;line-height:1.5;white-space:pre-wrap\">%s</div></details>",
				escHTML(m.ToolName), escHTML(content)))
		}
	}
	flushThinking()
	return out
}

// escHTML escapes special HTML characters to prevent injection.
func escHTML(s string) string {
	out := make([]byte, 0, len(s))
	for i := 0; i < len(s); i++ {
		switch s[i] {
		case '&':
			out = append(out, "&amp;"...)
		case '<':
			out = append(out, "&lt;"...)
		case '>':
			out = append(out, "&gt;"...)
		case '"':
			out = append(out, "&quot;"...)
		default:
			out = append(out, s[i])
		}
	}
	return string(out)
