// MessagesForDisplay returns simplified messages for the frontend.
func (s *Session) MessagesForDisplay() []DisplayMsg {
	out := make([]DisplayMsg, 0, len(s.Messages))
	for _, m := range s.Messages {
		switch m.Role {
