import (
	"fmt"
	"log"
	"sync"
)

// ContextManager handles context window limits and compression.
// Compression is based on user turns (one question = one turn), not raw message count.
type ContextManager struct {
	mu       sync.Mutex
	MaxTurns int // max user turns before compression
}

// NewContextManager creates a context manager with defaults.
func NewContextManager() *ContextManager {
	return &ContextManager{
		MaxTurns: 100,
	}
}

// CheckAndCompress checks if the session needs compression and applies it.
// Returns a summary of what was done.
func (cm *ContextManager) CheckAndCompress(sess *Session) string {
	userTurns := countUserMessages(sess.Messages)
	if userTurns <= cm.MaxTurns {
		return ""
	}

	cm.mu.Lock()
	defer cm.mu.Unlock()

	before := len(sess.Messages)

	// Group messages into turns. Each turn starts with a user message
	// and ends before the next user message (or end of messages).
	turns := groupTurns(sess.Messages)
	excess := len(turns) - cm.MaxTurns

	// Find the oldest N complete turns to summarize.
	// Skip the first turn if it's partial (system prompts, etc).
	summarizeEnd := excess
	if summarizeEnd < 1 {
		summarizeEnd = 1
	}
	if summarizeEnd > len(turns) {
		summarizeEnd = len(turns)
	}

	// Build a compact summary of the oldest turns.
	summary := compactSummary(turns[:summarizeEnd])

	// Rebuild messages: summary + remaining turns.
	var newMessages []Message
	newMessages = append(newMessages, Message{
		Role:    RoleSystem,
		Content: fmt.Sprintf("[Earlier conversation: %s]", summary),
	})
	for _, t := range turns[summarizeEnd:] {
