		return
	}

	// SSE headers.
	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("X-Accel-Buffering", "no")
	flusher, ok := w.(http.Flusher)
	if !ok {
		http.Error(w, "Streaming not supported", http.StatusInternalServerError)
		return
	}

	// Start agent Run in background, stream events back.
	ctx, cancel := context.WithTimeout(context.Background(), 300*time.Second)
	defer cancel()

	sid := req.SessionID
	msg := req.Message

	// Wire OnEvent to stream SSE events.
	origOnEvent := h.agent.OnEvent
	h.agent.OnEvent = func(evt agent.AgentEvent) {
		switch evt.Type {
		case agent.EventToolCall:
			sseEvent(w, "tool_call", evt.Data)
		case agent.EventToolResult:
			sseEvent(w, "tool_result", evt.Data)
		case agent.EventLLMStart:
