		case agent.EventError:
			sseEvent(w, "error", evt.Data)
		case agent.EventDone:
			sseEvent(w, "done", map[string]string{})
		}
	}
	defer func() { h.agent.OnEvent = origOnEvent }()

	result, err := h.agent.Run(ctx, sid, msg)
	if err != nil {
		sseEvent(w, "error", map[string]string{"message": err.Error()})
		sseEvent(w, "done", map[string]string{})
		return
	}
	if result.Error != "" {
		sseEvent(w, "error", map[string]string{"message": result.Error})
	}
	sseEvent(w, "done", map[string]string{})
	_ = flusher
}

